import{_ as o,o as t,c as a,ag as l}from"./chunks/framework.BbyMWZAR.js";const p=JSON.parse('{"title":"HMR 热更新是怎么实现的？","description":"","frontmatter":{"title":"HMR 热更新是怎么实现的？","difficulty":"hard","tags":["Webpack","HMR","dev-server","websocket"],"estimate":20},"headers":[],"relativePath":"domains/arch/qa/qa-04-hmr.md","filePath":"domains/arch/qa/qa-04-hmr.md","lastUpdated":1783504823000}'),r={name:"domains/arch/qa/qa-04-hmr.md"};function c(s,e,d,i,n,h){return t(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="问答-04-进阶-hmr-热更新是怎么实现的" tabindex="-1">问答 04（进阶）：HMR 热更新是怎么实现的？ <a class="header-anchor" href="#问答-04-进阶-hmr-热更新是怎么实现的" aria-label="Permalink to &quot;问答 04（进阶）：HMR 热更新是怎么实现的？&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>请解释 Webpack Hot Module Replacement（HMR）的工作原理：文件改动如何被检测、变化如何送到浏览器、模块如何被替换而不刷新页面？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>整体链路</strong></p><ol><li><strong>文件监听</strong>：<code>webpack-dev-server</code>（或 <code>webpack --watch</code>）用 <code>chokidar</code> 监听源文件变化。</li><li><strong>增量编译</strong>：改动触发新的 <code>compilation</code>，生成两类输出： <ul><li>一个 <strong>manifest 文件</strong>（<code>hash.hot-update.json</code>）：描述哪些 chunk 发生了变化。</li><li>一份或多份 <strong>update chunk 文件</strong>（<code>chunkId.hash.hot-update.js</code>）：新版本模块代码。</li></ul></li><li><strong>通知浏览器</strong>：dev-server 通过 <strong>WebSocket</strong>（老的 <code>sockjs</code> / 新的 <code>ws</code>）把 <code>hash</code> 广播给客户端。</li><li><strong>客户端拉更新</strong>：浏览器里的 HMR runtime（Webpack 打进 bundle 的一段代码）收到 hash 后，向服务端请求 manifest；根据 manifest 拉取对应的 update chunk。</li><li><strong>模块替换</strong>：拿到新模块后，HMR runtime 用它替换旧的模块记录（<code>module.exports</code>），并触发所有依赖它的模块调用 <code>module.hot.accept</code> 回调。</li><li><strong>兜底</strong>：如果链路上有模块<strong>没声明 <code>accept</code></strong>，HMR runtime 会一路&quot;冒泡&quot;到根，冒不到就整页刷新（<code>location.reload</code>）。</li></ol><p><strong>模块侧 API</strong></p><ul><li><code>module.hot.accept(dep, cb)</code>：告诉 runtime &quot;我能接受 dep 更新，用 cb 处理更新后的模块&quot;。</li><li><code>module.hot.dispose(cb)</code>：模块被替换前做清理（解绑事件、清定时器等）。</li><li><code>module.hot.decline()</code>：明确拒绝更新，改动此模块直接全刷新。</li><li>框架层（React Refresh、Vue HMR）已经封装好这些 API，业务代码通常不用手写。</li></ul><p><strong>关键细节</strong></p><ul><li>WebSocket 只传递事件（&quot;新 hash 到了&quot;），实际的更新代码走 HTTP。</li><li>Update chunk 是<strong>增量</strong>的，只包含变更后的模块，不重发全量 bundle。</li><li>服务端把这些 hot-update 文件保存在内存（memory-fs / memfs），不落盘。</li><li>Webpack Dev Middleware 提供 <code>/hash.hot-update.json</code> 和 <code>/chunk.hot-update.js</code> 的 URL，静态路径解析到内存文件系统。</li></ul><p><strong>为什么能&quot;不丢状态&quot;</strong></p><ul><li>因为整个页面没有刷新，只是替换了 JS 模块的实现。React/Vue 的 state、路由状态、表单输入都保留在旧组件树里。</li><li>React Fast Refresh / Vue Hot Reload 会尝试<strong>保持组件状态</strong>同时更新渲染逻辑；hooks / setup 语义变化时会触发重挂载。</li></ul><h2 id="追问-1-为什么改样式-css-scss-能-无感更新" tabindex="-1">追问 1：为什么改样式（CSS/SCSS）能&quot;无感更新&quot;？ <a class="header-anchor" href="#追问-1-为什么改样式-css-scss-能-无感更新" aria-label="Permalink to &quot;追问 1：为什么改样式（CSS/SCSS）能&quot;无感更新&quot;？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>CSS 走的是 <code>style-loader</code> 提供的 HMR 逻辑： <ul><li>开发时 <code>style-loader</code> 把 CSS 内容通过 <code>&lt;style&gt;</code> 标签注入 <code>document.head</code>。</li><li><code>style-loader</code> 主动调用 <code>module.hot.accept</code>，模块更新时把旧的 <code>&lt;style&gt;</code> 元素移除，插入新的。</li></ul></li><li>因此 CSS 更新不会引起 JS 重挂载，DOM 状态完全保留。</li><li>生产环境走 <code>MiniCssExtractPlugin</code> 抽成独立文件，就没有 HMR 的事了。</li><li>如果用 CSS Modules 或 CSS-in-JS：CSS Modules 生成的类名依赖 hash，注入模式和普通 CSS 类似；CSS-in-JS 的 HMR 依赖具体库（emotion/styled-components）的支持。</li></ul><h2 id="追问-2-react-的-fast-refresh-相比-普通-hmr-多做了什么" tabindex="-1">追问 2：React 的 Fast Refresh 相比&quot;普通 HMR&quot;多做了什么？ <a class="header-anchor" href="#追问-2-react-的-fast-refresh-相比-普通-hmr-多做了什么" aria-label="Permalink to &quot;追问 2：React 的 Fast Refresh 相比&quot;普通 HMR&quot;多做了什么？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>保持组件状态</strong>：普通 HMR 用新模块直接替换旧的，React 组件树会被&quot;重挂载&quot;，state / hooks 状态丢失。Fast Refresh 会分析新代码 export 的组件： <ul><li>如果是纯组件（函数组件、<code>React.memo</code>、<code>forwardRef</code>）：<strong>只更新组件实现，不 unmount</strong>，state 保留。</li><li>如果 hook 顺序 / 类型变化，或 export 里包含非组件（导出的函数被改），fallback 到重挂载。</li></ul></li><li><strong>错误边界</strong>：Fast Refresh 会捕获 module 更新时的错误，展示错误 overlay，修复后自动恢复。</li><li><strong>依赖识别</strong>：通过 <code>react-refresh/babel</code> 插件在函数组件外围包一层&quot;注册代码&quot;，运行时能识别哪些是组件、哪些是普通导出。</li><li>结果：改一个组件，页面不闪、state 不丢、错误提示友好。</li></ul><h2 id="追问-3-hmr-和-live-reload-有什么区别-为什么有时候还是会整页刷新" tabindex="-1">追问 3：HMR 和 Live Reload 有什么区别？为什么有时候还是会整页刷新？ <a class="header-anchor" href="#追问-3-hmr-和-live-reload-有什么区别-为什么有时候还是会整页刷新" aria-label="Permalink to &quot;追问 3：HMR 和 Live Reload 有什么区别？为什么有时候还是会整页刷新？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>Live Reload</strong>：文件变化直接 <code>location.reload()</code>，全页刷新，state 全丢。</li><li><strong>HMR</strong>：只替换变更的模块，state 尽量保留。</li><li>为什么 HMR 会退化到 Live Reload： <ol><li>项目里没有任何模块声明 <code>module.hot.accept</code>，冒泡到根还没人处理，只能刷新。</li><li>模块类型不支持热替换（例如改了 webpack config、public/index.html）。</li><li>改动了模块的 exports 结构（新增 default export、改变函数签名），框架的 Fast Refresh 判断无法安全保状态，触发 full reload。</li><li>依赖循环或多入口共享模块时，链路太复杂 runtime 兜底刷新。</li><li><code>webpack-dev-server</code> 配置中 <code>hot: false</code> 或 <code>liveReload: true</code>。</li></ol></li><li>排查：看浏览器控制台的 <code>[HMR]</code> 日志，Webpack 5 dev-server 会打印&quot;module accepted&quot; / &quot;no accept found, reloading&quot;。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/arch/RESOURCES">工程架构 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://webpack.js.org/concepts/hot-module-replacement/" target="_blank" rel="noreferrer">Webpack: Hot Module Replacement</a>：<code>module.hot.accept</code>、更新传播链路与 fallback 到整页刷新的官方说明。</li><li><a href="https://vite.dev/guide/api-hmr.html" target="_blank" rel="noreferrer">Vite: HMR API</a>：<code>import.meta.hot</code> 与框架无关的热更新接口。</li><li><a href="https://react.dev/learn/react-compiler#fast-refresh" target="_blank" rel="noreferrer">React Fast Refresh</a>：React 组件级热更新如何保留 state 的原理概述。</li></ul>',24)])])}const m=o(r,[["render",c]]);export{p as __pageData,m as default};
